public boolean canJump(int[] nums) {
    boolean[] dp = new boolean[nums.length];
    dp[0] = true;
    for (int i = 0; i < nums.length; i++) {
        if (!dp[i]) continue;
        for (int j = i + 1; j <= Math.min(i + nums[i], nums.length - 1); j++) {
            dp[j] = true;
        }
    }
    return dp[nums.length - 1];
}

