from typing import List

def can_jump(nums: List[int]) -> bool:
    n = len(nums)
    dp = [False] * n
    dp[0] = True
    for i in range(n):
        if not dp[i]:
            continue
        for j in range(i + 1, min(i + nums[i] + 1, n)):
            dp[j] = True
    return dp[n - 1]
